={{ (function() {
  var step = $('Loop Over Steps').item.json.step;
  var reportId = $('Parse Plan & Generate Report ID').item.json.report_id.replace(/[^a-zA-Z0-9_]/g, '_');
  var sql = (step.query_strategy && (step.query_strategy.sql || step.query_strategy.logic)) || 'SELECT 1';
  sql = sql.replace(/\bstep(\d+)\b/gi, function(m, n) {
    return 'n8n_data."tmp_' + reportId + '_step_' + n + '"';
  });
  sql = sql.trim().replace(/;+\s*$/g, '');
  // Fix invalid empty-string comparisons that fail on integer/bigint columns
  // e.g.: "customer_id" <> '' → "customer_id" IS NOT NULL
  sql = sql.replace(/"([^"]+)"\s*(?:!=|<>)\s*''/g, '"$1" IS NOT NULL');
  sql = sql.replace(/"([^"]+)"\s*=\s*''/g, '"$1" IS NULL');
  // Fix TRIM("col") <> '' on integer columns
  sql = sql.replace(/TRIM\("([^"]+)"\)\s*(?:!=|<>)\s*''/gi, '"$1" IS NOT NULL');
  sql = sql.replace(/TRIM\("([^"]+)"\)\s*=\s*''/gi, '"$1" IS NULL');
  var tableName = 'n8n_data."tmp_' + reportId + '_step_' + step.step_number + '"';
  return 'CREATE TABLE ' + tableName + ' AS ' + sql;
})() }}

