const items = $input.all();
if (items.length > 0 && items[0].json && items[0].json.dep_column_info !== undefined) {
  return [{ json: { dep_column_info: items[0].json.dep_column_info || 'None' } }];
}
const rows = items.filter(item => item.json && item.json.table_name);
const depColumnInfo = rows.length > 0
  ? rows.map(r => 'n8n_data."' + r.json.table_name + '": ' + r.json.columns).join('\n')
  : 'None';
return [{ json: { dep_column_info: depColumnInfo } }];

const items = $input.all();

// Check for node execution errors (from onError: continueRegularOutput on Execute Direct SQL)
if (items.length > 0 && items[0].json.error) {
  const err = items[0].json.error;
  let errMsg;
  if (typeof err === 'string') {
    errMsg = err;
  } else {
    // Capture actual PostgreSQL error (cause.message) plus query info
    const causeMsg = (err.cause && err.cause.message) || null;
    const mainMsg = err.message || null;
    const desc = typeof err.description === 'string' ? err.description : null;
    if (causeMsg && mainMsg && causeMsg !== mainMsg) {
      // Both present: show DB error + query context
      errMsg = causeMsg + ' | Query: ' + mainMsg.slice(0, 300);
    } else {
      errMsg = causeMsg || mainMsg || desc || JSON.stringify(err).slice(0, 400);
    }
  }
  return [{ json: { output: null, error: 'List step SQL failed: ' + errMsg }, pairedItem: { item: 0 } }];
}

if (!items || items.length === 0) {
  return [{ json: { output: 'No results returned.' }, pairedItem: { item: 0 } }];
}

const rows = items.map(i => i.json);
const headers = Object.keys(rows[0]);

// Build 10-row preview as markdown table
const headerRow = '| ' + headers.join(' | ') + ' |';
const separator = '| ' + headers.map(() => '---').join(' | ') + ' |';
const previewRows = rows.slice(0, 10).map(row =>
  '| ' + headers.map(h => {
    const val = row[h];
    return val === null || val === undefined ? '' : String(val).replace(/\|/g, '\\|');
  }).join(' | ') + ' |'
);
const preview = [headerRow, separator, ...previewRows].join('\n');
const previewNote = rows.length > 10
  ? `\n_Showing 10 of ${rows.length} rows — full data available as download_`
  : '';

// Build full CSV
const escapeCSV = v => {
  const s = String(v ?? '');
  if (s.includes(',') || s.includes('"') || s.includes('\n') || s.includes('\r')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
};
const csvLines = [
  headers.map(escapeCSV).join(','),
  ...rows.map(row => headers.map(h => escapeCSV(row[h])).join(','))
];
const csvData = csvLines.join('\n');
const csvB64 = Buffer.from(csvData).toString('base64');

const output = `**Full List (${rows.length} rows)**\n\n${preview}${previewNote}\n<!--LIST_CSV:${csvB64}-->`;

return [{ json: { output }, pairedItem: items.map((_, i) => ({ item: i })) }];

